#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        char s[100005];
        scanf("%s", s);
        int n = strlen(s);
        int *lps = (int*)calloc(n, sizeof(int));
        int len = 0;
        for(int i=1;i<n;){
            if(s[i]==s[len]){ len++; lps[i]=len; i++; }
            else if(len!=0){ len = lps[len-1]; }
            else{ lps[i]=0; i++; }
        }
        int happy = lps[n-1];
        for(int i=0;i<happy;i++) putchar(s[i]);
        putchar('\n');
        free(lps);
    }
    return 0;
}

