import sys

def longest_happy_prefix(s: str) -> str:
    n = len(s)
    lps = [0] * n
    length = 0
    i = 1
    while i < n:
        if s[i] == s[length]:
            length += 1
            lps[i] = length
            i += 1
        else:
            if length != 0:
                length = lps[length - 1]
            else:
                lps[i] = 0
                i += 1
    return s[:lps[-1]]

data = sys.stdin.read().splitlines()
if not data:
    sys.exit()
T = int(data[0])
out = []
for i in range(1, T + 1):
    out.append(longest_happy_prefix(data[i].strip()))
print('\n'.join(out))

