const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function longestHappyPrefix(s) {
    const n = s.length;
    const lps = new Int32Array(n);
    let len = 0;
    for (let i = 1; i < n;) {
        if (s.charCodeAt(i) === s.charCodeAt(len)) {
            len++;
            lps[i] = len;
            i++;
        } else if (len !== 0) {
            len = lps[len - 1];
        } else {
            lps[i] = 0;
            i++;
        }
    }
    const happy = lps[n - 1];
    return happy > 0 ? s.substring(0, happy) : '';
}
const T = parseInt(lines[idx++]);
let output = [];
while (T--) {
    const s = lines[idx++] || '';
    output.push(longestHappyPrefix(s));
}
